+    if (e.key === STORAGE_KEY && e.newValue) {
+      try {
+        const parsed = JSON.parse(e.newValue) as unknown;
+        if (isRecord(parsed)) {
+          readingStore.setState(() => ({ positions: sanitizePositions(parsed.positions) }));
